import{ad as o,o as t,c as a,aw as c}from"./chunks/framework.Docx9Nvx.js";const h=JSON.parse('{"title":"Legacy components","description":"","frontmatter":{},"headers":[],"relativePath":"docs/components/legacy.md","filePath":"docs/components/legacy.md","lastUpdated":1777304650000}'),d={name:"docs/components/legacy.md"};function r(n,e,l,s,p,i){return t(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="legacy-components" tabindex="-1">Legacy components <a class="header-anchor" href="#legacy-components" aria-label="Permalink to “Legacy components”">​</a></h1><p>These components are deprecated and emit a <code>console.warn</code> in development. They remain in the library for now to keep existing apps building, but new code should use the replacements listed below. Each will be removed in a future major release.</p><h2 id="input" tabindex="-1">Input <a class="header-anchor" href="#input" aria-label="Permalink to “Input”">​</a></h2><p>Replaced by <a href="./textinput"><code>TextInput</code></a> for text-like inputs (<code>text</code>, <code>number</code>, <code>email</code>, <code>password</code>, <code>date</code>), <a href="./textarea"><code>Textarea</code></a>, <a href="./select"><code>Select</code></a>, and <a href="./checkbox"><code>Checkbox</code></a> for the other type modes the original <code>Input</code> accepted.</p><p><code>TextInput</code> and friends share a labeling contract (<code>label</code>, <code>description</code>, <code>error</code>, <code>required</code>) and a sized/variant API that the legacy <code>Input</code> component does not.</p><h2 id="autocomplete" tabindex="-1">Autocomplete <a class="header-anchor" href="#autocomplete" aria-label="Permalink to “Autocomplete”">​</a></h2><p>Replaced by <a href="./combobox"><code>Combobox</code></a> for single-select and <a href="./multiselect"><code>MultiSelect</code></a> for multi-select usage.</p><p><code>Combobox</code> and <code>MultiSelect</code> use the shared input primitives, render the same label/description/error contract as the rest of the v1 input family, and have a smaller, more predictable API surface.</p><h2 id="formcontrol-with-type-autocomplete" tabindex="-1">FormControl with <code>type=&quot;autocomplete&quot;</code> <a class="header-anchor" href="#formcontrol-with-type-autocomplete" aria-label="Permalink to “FormControl with type=&quot;autocomplete&quot;”">​</a></h2><p><code>FormControl</code> itself is not deprecated, but the <code>autocomplete</code> value for its <code>type</code> prop is. Use <a href="./combobox"><code>Combobox</code></a> directly instead — the combobox path inside <code>FormControl</code> already proxies to it, and a standalone <code>Combobox</code> exposes the full set of slots and props without the wrapper layer.</p>',10)])])}const u=o(d,[["render",r]]);export{h as __pageData,u as default};
